5: /// Best-effort language detection for a diff view. Returns a token suitable
6: /// for `markdown::highlight_code_raw` (typically the file extension, falling
7: /// back to the filename for ext-less files like `Makefile`/`Dockerfile`).
8: /// Returns `None` for empty paths or paths with no recognizable token.
9: ///
10: /// The returned string is *not* guaranteed to map to a real syntect syntax —
11: /// `highlight_code_raw` will fall back to plain text for unknowns. Keeping
12: /// this lossy on purpose: matching the syntect set up front would couple this
13: /// helper to syntect's loaded syntaxes, but the highlighter already does that
14: /// resolution downstream and degrades gracefully.
15: pub fn diff_lang(diff: &DiffView) -> Option<String> {
16:     let p = std::path::Path::new(&diff.file_path);
17:     if let Some(ext) = p.extension().and_then(|e| e.to_str())
18:         && !ext.is_empty()
19:     {
20:         return Some(ext.to_string());
21:     }
22:     // No extension — fall back to the filename (lowercased) so things like
23:     // `Makefile` / `Dockerfile` / `Rakefile` get a chance to resolve via
24:     // syntect's by-name / by-token lookup.
25:     p.file_name()
26:         .and_then(|f| f.to_str())
27:         .map(|f| f.to_lowercase())
28:         .filter(|s| !s.is_empty())
29: }
